        /// <summary>
        /// Gets the Unicode code point for a Material Symbol icon
        /// </summary>
        /// <param name="kind">The icon kind</param>
        /// <param name="variant">The icon variant (Outlined, Rounded, Sharp)</param>
        /// <param name="filled">Whether to use the filled version</param>
        /// <returns>Unicode code point as hex string (e.g., "E88A")</returns>
        public static string GetCodePoint(MaterialSymbolKind kind, MaterialSymbolVariant variant, bool filled)
        {
            // Most icons share the same code point across variants
            // The font handles the visual variant through OpenType features
            if (_codePoints.TryGetValue(kind, out var codePoint))
            {
                return codePoint;
            }

            // Fallback to Home icon if not found
            return "E88A";
        }

        /// <summary>
        /// Gets all available icon kinds
        /// </summary>
        public static IEnumerable<MaterialSymbolKind> GetAllKinds()
        {
            return _codePoints.Keys;
        }

        /// <summary>
        /// Checks if an icon kind is available
        /// </summary>
        public static bool IsAvailable(MaterialSymbolKind kind)
        {
            return _codePoints.ContainsKey(kind);
        }
    }
